+  test('UserGroupAddEvent, UserGroupRemoveEvent', () async {
+    final group1 = eg.userGroup();
+    final store = eg.store(initialSnapshot: eg.initialSnapshot(
+      realmUserGroups: [group1]));
+    checkGroupsEqual(store, [group1]);
+
+    final group2 = eg.userGroup();
+    await store.handleEvent(UserGroupAddEvent(id: 1, group: group2));
+    checkGroupsEqual(store, [group1, group2]);
+
+    await store.handleEvent(UserGroupRemoveEvent(id: 2, groupId: group1.id));
+    checkGroupsEqual(store, [group2]);
+  });
+
+  test('UserGroupUpdateEvent', () async {
+    final store = eg.store();
+    final group = eg.userGroup(
+      name: 'a group', description: 'is a group', deactivated: false);
+    await store.handleEvent(UserGroupAddEvent(id: 1, group: group));
+    checkGroupsEqual(store, [group]);
+
+    // Handles all the properties being updated at once.
+    await store.handleEvent(UserGroupUpdateEvent(id: 2, groupId: group.id,
+      data: UserGroupUpdateData(name: 'revised group',
+        description: 'different description', deactivated: true)));
+    checkGroupsEqual(store, [{
+      ...group.toJson(),
+      'name': 'revised group',
+      'description': 'different description',
+      'deactivated': true,
+    }]);
+
+    // Handles some properties being null, still updating the one that's present.
+    await store.handleEvent(UserGroupUpdateEvent(id: 2, groupId: group.id,
+      data: UserGroupUpdateData(name: null,
+        description: null, deactivated: false)));
+    checkGroupsEqual(store, [{
+      ...group.toJson(),
+      'name': 'revised group',
+      'description': 'different description',
+      'deactivated': false,
+    }]);
+  });
+
+  test('various fields make it through', () async {
+    final store = eg.store(initialSnapshot: eg.initialSnapshot(
+      realmUserGroups: [
+        eg.userGroup(id: 3, name: 'some group', description: 'this is a group',
+          isSystemGroup: true, deactivated: false),
+      ]));
+    await store.handleEvent(UserGroupAddEvent(id: 1, group: eg.userGroup(
+      id: 5, name: 'a different group', description: 'also a group',
+      isSystemGroup: false, deactivated: true)));
+    check(sorted(store.allGroups)).deepEquals(<Condition<Object?>>[
+      (it) => it.isA<UserGroup>()
+        ..id.equals(3)
+        ..name.equals('some group')
+        ..description.equals('this is a group')
+        ..isSystemGroup.isTrue()
+        ..deactivated.isFalse(),
+      (it) => it.isA<UserGroup>()
+        ..id.equals(5)
+        ..name.equals('a different group')
+        ..description.equals('also a group')
+        ..isSystemGroup.isFalse()
+        ..deactivated.isTrue(),
+    ]);
+  });
+}

body:
Fixes #979.

Discussion:
  https://github.com/zulip/zulip-flutter/issues/979#issuecomment-2993296322

------

Tested manually, with and without this change:

1. Log out from CZO (too active; events coming in frequently); connect to a not-very-active org

2. Make an artificial network error in the `getEvents` binding:

```diff
diff --git lib/api/route/events.dart lib/api/route/events.dart
index bd14521c7..da7bf4fea 100644
--- lib/api/route/events.dart
+++ lib/api/route/events.dart
@@ -1,6 +1,7 @@
 import 'package:json_annotation/json_annotation.dart';
 
 import '../core.dart';
+import '../exception.dart';
 import '../model/events.dart';
 import '../model/initial_snapshot.dart';
 
@@ -27,6 +28,7 @@ Future<InitialSnapshot> registerQueue(ApiConnection connection) {
 Future<GetEventsResult> getEvents(ApiConnection connection, {
   required String queueId, int? lastEventId, bool? dontBlock,
 }) {
+  throw NetworkException(routeName: 'foo', message: 'foo', cause: 'foo');
   return connection.get('getEvents', GetEventsResult.fromJson, 'events', {
     'queue_id': RawParameter(queueId),
     if (lastEventId != null) 'last_event_id': lastEventId,
```

3. Watch the logs to see retries going by
4. Comment out the `throw NetworkException` line and do a hot-reload
5. Watch the logs for `dont_block` in the `GET /events`, and watch the app to see if the loading indicator goes away quickly
   - Without the change, I don't see `dont_block`, and the loading indicator doesn't go away until the next event comes in
   - With the change, I see `dont_block`, and the loading indicator goes away quickly

